.forge-topbar img, .forge-topbar video, .forge-topbar svg, .forge-topbar picture {max-width:100%;height:auto}

.forge-topbar main {width:100%;display:flex;flex-direction:column}

.forge-topbar .section-inner {max-width:2160px;margin:0 auto;width:100%}

.forge-topbar .t-title-28 {font-family:"Adobe Clean",sans-serif;font-weight:700;font-size:28px;line-height:35px}

.forge-topbar .t-btn-14 {font-family:"Adobe Clean",sans-serif;font-weight:500;font-size:14px;line-height:18px}

.forge-topbar {min-height:80px}

.forge-topbar .topbar-bar {display:flex;justify-content:center;align-items:center;gap:64px;width:100%;height:80px;
  background:var(--palette-gray-50);border-radius:16px}

.forge-topbar .topbar-title {margin:0;color:var(--color-2c2c2c);text-align:center}

.forge-topbar .topbar-nav {display:flex;gap:16px}

.forge-topbar .tb-btn {display:inline-flex;align-items:center;height:32px;padding:6px 12px 8px;border:0;border-radius:8px;
  background:var(--color-e9e9e9);color:var(--color-292929);cursor:pointer}

.forge-topbar .tb-btn.is-active {background:var(--color-292929);color:#fff}

.forge-topbar .bd-links .bd-link.is-active {color:#2c2c2c;font-weight:600}

.forge-topbar .bd-links .bd-link.is-active::after {content:"";position:absolute;left:0;right:0;bottom:-22px;height:3px;background:#2c2c2c}

@media (max-width:1023px) {
.forge-topbar .topbar-bar {flex-direction:column;gap:20px;height:auto;padding:20px 16px}
.forge-topbar .topbar-nav {flex-wrap:wrap;justify-content:center}
}

